#!/usr/bin/env python3
"""Grade 12, Days 101-110 -- extends Grade 12 from 100 to 110 days. Topics
chosen to avoid any overlap with the existing Day 1-100 set (see
data/grade12.json): reader-response theory, the Gothic novel and the
uncanny, psychoanalytic literary criticism, the dramatic monologue, New
Historicism, the villanelle, Marxist literary criticism, the epigraph
and paratext, slam poetry and the oral tradition, and queer theory;
Wilson’s theorem, the remainder theorem and synthetic division, the
chi-squared goodness-of-fit test, partial fraction decomposition, the
sieve of Eratosthenes, the Intermediate Value Theorem, graph colouring
and the chromatic number, symmetric functions, perfect numbers and
Mersenne primes, and the inclusion-exclusion principle; the comparison
test for series, first-order linear differential equations and
integrating factors, the binomial series, conservative vector fields
and the fundamental theorem of line integrals, triple integrals in
cylindrical coordinates, Pappus’s theorem, the Frenet-Serret formulas,
the divergence (nth-term) test, Jacobians and change of variables, and
the method of Frobenius; the Rutherford gold foil experiment, the
Millikan oil drop experiment, the Stefan-Boltzmann law, X-ray
diffraction and Bragg’s law, terminal velocity and drag, the Carnot
cycle, radiation pressure and solar sails, the Van Allen belts,
electrostatic shielding and the Faraday cage, and eddy currents.

Subject keys for Grade 12 are "English", "AdvancedFunctions",
"Calculus", "Physics" (same as all earlier Grade 12 batches).

videoUrl is intentionally left unset for every subject --
fetch_video_ids.py fills these in automatically on its next daily run.
No embedded ASCII double-quote characters are used anywhere in
question/summary/option text; apostrophes use the curly Unicode form
(’).
"""
import sys, os
sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from gen_curriculum import sub, day, append_to

E12 = 'https://tvolearn.com/pages/grade-12-english'
AF12 = 'https://tvolearn.com/pages/grade-12-advanced-functions'
CA12 = 'https://tvolearn.com/pages/grade-12-calculus-and-vectors'
PH12 = 'https://tvolearn.com/pages/grade-12-physics'
RE, RAF, RCA, RPH = (
    'TVO Learn: Grade 12 English',
    'TVO Learn: Grade 12 Advanced Functions',
    'TVO Learn: Grade 12 Calculus and Vectors',
    'TVO Learn: Grade 12 Physics',
)


def E(t, s, q):
    return sub('English', t, s, RE, E12, q)


def AF(t, s, q):
    return sub('AdvancedFunctions', t, s, RAF, AF12, q)


def CA(t, s, q):
    return sub('Calculus', t, s, RCA, CA12, q)


def PH(t, s, q):
    return sub('Physics', t, s, RPH, PH12, q)


def _rebalance_answer_positions(days, seed=20261001):
    import random
    rng = random.Random(seed)
    quizzes = [sub_entry[5] for _, subs in days for sub_entry in subs]
    n = sum(len(q) for q in quizzes)
    targets = [i % 4 for i in range(n)]
    rng.shuffle(targets)
    idx = 0
    for quiz in quizzes:
        for i, (q, opts, ans) in enumerate(quiz):
            correct_text = opts[ans]
            wrong_texts = [o for j, o in enumerate(opts) if j != ans]
            rng.shuffle(wrong_texts)
            target = targets[idx]
            idx += 1
            new_opts = [None, None, None, None]
            new_opts[target] = correct_text
            wi = 0
            for slot in range(4):
                if new_opts[slot] is None:
                    new_opts[slot] = wrong_texts[wi]
                    wi += 1
            quiz[i] = (q, new_opts, target)
    return days


